// ── ETL Transform: Normalise, Clean, Validate ─────────────────────
// This node standardises field names, converts types,
// handles nulls, deduplicates, and adds metadata.

const rawRecords = $input.all();
const errors = [];
const transformed = [];

// Helper: safe string normalisation
const safe = (val, fallback = '') => (val !== null && val !== undefined) ? String(val).trim() : fallback;
const safeNum = (val, fallback = 0) => isNaN(Number(val)) ? fallback : Number(val);
const safeDate = (val) => { try { return new Date(val).toISOString(); } catch { return null; } };

// Track seen IDs for deduplication
const seen = new Set();

for (const item of rawRecords) {
  // Handle both array responses and nested data
  const records = Array.isArray(item.json) ? item.json : (item.json.data || item.json.records || [item.json]);

  for (const r of records) {
    try {
      // Skip duplicates within this batch
      if (seen.has(r.id)) continue;
      seen.add(r.id);

      // ── Map to your DB schema ──────────────────────────────────────
      // EDIT THESE FIELD MAPPINGS to match your source API and DB columns
      transformed.push({
        json: {
          external_id:   safe(r.id),
          name:          safe(r.name || r.title),
          email:         safe(r.email || r.contact_email),
          company:       safe(r.company || r.organisation),
          status:        safe(r.status, 'unknown'),
          amount:        safeNum(r.amount || r.value),
          created_at:    safeDate(r.created_at || r.createdAt),
          updated_at:    safeDate(r.updated_at || r.updatedAt),
          ingested_at:   new Date().toISOString(),
          source:        'api_etl_pipeline'
        }
      });
    } catch (err) {
      errors.push({ id: r.id || 'unknown', error: err.message });
    }
  }
}

// Attach error summary to first item for downstream checking
if (transformed.length > 0) {
  transformed[0].json._meta = {
    total_transformed: transformed.length,
    error_count: errors.length,
    errors: errors
  };
}

return transformed;

